const items = $input.all();

const allowedCategories = new Set([
  "LLM", "Agents", "RAG", "Evaluation", "Multimodal",
  "Coding", "Productivity", "Research Tools", "Automation"
]);

const allowedActions = new Set(["Test", "Watch", "Ignore"]);

const clampScore = (value) => {
  const n = Number(value);
  if (!Number.isFinite(n)) return 0;
  return Math.max(1, Math.min(10, Math.round(n)));
};

const safeText = (value, fallback) => {
  const text = String(value ?? "").trim();
  return text || fallback;
};

const hashText = (text) => {
  let hash = 5381;
  for (let i = 0; i < text.length; i++) {
    hash = ((hash << 5) + hash) + text.charCodeAt(i);
    hash = hash >>> 0;
  }
  return `h_${hash.toString(16)}`;
};

return items.map((item, idx) => {
  let parsed;

  try {
    parsed = JSON.parse(item.json.ai_raw || "{}");
  } catch (e) {
    parsed = {
      category: "unknown",
      lab_relevance: 0,
      practicality: 0,
      novelty: 0,
      recommended_action: "Pending",
      why_it_matters: "Parsing failed"
    };
  }

  const rawCategory = safeText(parsed.category, "unknown");
  const category = allowedCategories.has(rawCategory) ? rawCategory : "unknown";

  const rawAction = safeText(parsed.recommended_action, "Pending");
  const recommended_action = allowedActions.has(rawAction) ? rawAction : "Watch";

  const lab = clampScore(parsed.lab_relevance);
  const prac = clampScore(parsed.practicality);
  const nov = clampScore(parsed.novelty);

  const final_score = Number(((lab + prac + nov) / 3).toFixed(2));
  const why_it_matters = safeText(parsed.why_it_matters, "Pending").slice(0, 220);

  const title = safeText(item.json.title, "untitled").toLowerCase();
  const url = safeText(item.json.url, "").toLowerCase();
  const hash_id = hashText(`${title}|${url}`);

  return {
    json: {
      id: `${new Date().toISOString()}-${idx}`,
      ...item.json,
      hash_id,
      category,
      lab_relevance: lab,
      practicality: prac,
      novelty: nov,
      final_score,
      recommended_action,
      why_it_matters
    }
  };
});

const allItems = $input.all().map(item => item.json);

const now = new Date();
const DAYS_30 = 1000 * 60 * 60 * 24 * 30;

function isRecent(dateStr) {
  if (!dateStr) return false;
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return false;
  return (now - d) <= DAYS_30;
}

const filtered = allItems
  .filter(row => {
    const score = Number(row.final_score || 0);
    const action = row.recommended_action || "";
    const why = row.why_it_matters || "";

    if (!row.title) return false;
    if (!row.category) return false;
    if (!why) return false;
    if (why === "Parsing failed") return false;
    if (!isRecent(row.published_date)) return false;

    return action === "Test" || score >= 6;
  })
  .sort((a, b) => Number(b.final_score || 0) - Number(a.final_score || 0))
  .slice(0, 6);

return filtered.map(row => ({
  json: {
    ...row,
    total_scanned: allItems.length,
    total_selected: filtered.length
  }
}));

const items = $input.all().map(i => i.json);

const sorted = items.sort((a, b) => Number(b.final_score || 0) - Number(a.final_score || 0));
const topPick = sorted[0] || null;
const rest = sorted.slice(1);

const totalScanned = sorted[0]?.total_scanned || items.length;
const totalSelected = sorted[0]?.total_selected || items.length;

const testItems = rest.filter(x => x.recommended_action === "Test");
const watchItems = rest.filter(x => x.recommended_action === "Watch");

const actionColor = (action) => {
  if (action === "Test") return "#16a34a";
  if (action === "Watch") return "#d97706";
  return "#6b7280";
};

const actionBg = (action) => {
  if (action === "Test") return "#dcfce7";
  if (action === "Watch") return "#fef3c7";
  return "#f3f4f6";
};

const badgeBg = (score) => {
  const s = Number(score || 0);
  if (s >= 7) return "#dcfce7";
  if (s >= 6) return "#fef3c7";
  return "#f3f4f6";
};

const sourceIcon = (source) => {
  if (source === "HackerNews") return "🟠";
  if (source === "ProductHunt") return "🟣";
  if (source === "GitHub") return "⚫";
  if (source === "arXiv") return "🔵";
  return "•";
};

function renderCard(item, indexLabel = "") {
  return `
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="border:1px solid #e5e7eb; border-radius:16px; background:#ffffff; margin-bottom:18px;">
      <tr>
        <td style="padding:20px;">
          ${indexLabel ? `<div style="font-size:12px; color:#6b7280; margin-bottom:8px;">${indexLabel}</div>` : ""}
          <div style="font-size:24px; line-height:1.3; font-weight:800; color:#111827; margin-bottom:12px;">
            ${item.title}
          </div>
          <div style="margin-bottom:14px;">
            <span style="display:inline-block; background:${badgeBg(item.final_score)}; color:#111827; font-size:12px; font-weight:700; padding:6px 10px; border-radius:999px; margin-right:8px;">
              Score: ${item.final_score}
            </span>
            <span style="display:inline-block; background:#eef2ff; color:#4338ca; font-size:12px; font-weight:700; padding:6px 10px; border-radius:999px; margin-right:8px;">
              ${item.category}
            </span>
            <span style="display:inline-block; background:${actionBg(item.recommended_action)}; color:${actionColor(item.recommended_action)}; font-size:12px; font-weight:700; padding:6px 10px; border-radius:999px; margin-right:8px;">
              ${item.recommended_action}
            </span>
          </div>
          <div style="font-size:14px; line-height:1.7; color:#374151; margin-bottom:14px;">
            <b style="color:#111827;">Why it matters:</b> ${item.why_it_matters}
          </div>
          <div style="font-size:13px; line-height:1.7; color:#4b5563; margin-bottom:14px;">
            <b style="color:#111827;">Source:</b> ${sourceIcon(item.source)} ${item.source}<br>
            <b style="color:#111827;">Published:</b> ${item.published_date}
          </div>
          ${item.url ? `<a href="${item.url}" style="display:inline-block; background:#111827; color:#ffffff; text-decoration:none; font-size:14px; font-weight:700; padding:10px 16px; border-radius:10px;">Open item</a>` : ""}
        </td>
      </tr>
    </table>
  `;
}

const testSection = testItems.length
  ? testItems.map((item, idx) => renderCard(item, `Worth testing #${idx + 1}`)).join("")
  : `<p style="font-size:14px; color:#6b7280;">No strong Test items this cycle.</p>`;

const watchSection = watchItems.length
  ? watchItems.map((item, idx) => renderCard(item, `Worth watching #${idx + 1}`)).join("")
  : `<p style="font-size:14px; color:#6b7280;">No Watch items this cycle.</p>`;

const body = `
<!DOCTYPE html>
<html>
  <body style="margin:0; padding:0; background:#f3f4f6; font-family:Arial, Helvetica, sans-serif;">
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#f3f4f6; padding:24px 0;">
      <tr>
        <td align="center">
          <table role="presentation" width="700" cellpadding="0" cellspacing="0" style="max-width:700px; width:700px;">
            <tr>
              <td style="padding:0 16px 20px 16px;">
                <table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:linear-gradient(135deg,#111827,#1f2937); border-radius:20px; overflow:hidden;">
                  <tr>
                    <td style="padding:30px 28px 24px 28px;">
                      <div style="font-size:12px; letter-spacing:1px; text-transform:uppercase; color:#c7d2fe; font-weight:700; margin-bottom:10px;">
                        Weekly Lab Radar
                      </div>
                      <div style="font-size:32px; line-height:1.2; color:#ffffff; font-weight:800; margin-bottom:10px;">
                        AI Tool Radar
                      </div>
                      <div style="font-size:15px; line-height:1.6; color:#d1d5db; margin-bottom:10px;">
                        A curated weekly digest of tools, repos, and papers worth reviewing for the lab.
                      </div>
                      <div style="font-size:13px; color:#e5e7eb; line-height:1.6;">
                        🧠 ${totalScanned} items scanned → ${totalSelected} selected → 1 top pick
                      </div>
                    </td>
                  </tr>
                </table>
              </td>
            </tr>

            ${topPick ? `
            <tr>
              <td style="padding:0 16px 10px 16px;">
                <div style="font-size:20px; font-weight:800; color:#111827; margin:8px 0 14px 2px;">
                  🏆 Top pick of the week
                </div>
                ${renderCard(topPick, "Top pick #1")}
              </td>
            </tr>
            ` : ""}

            <tr><td style="padding:0 16px 8px 16px;"><hr style="border:none; border-top:1px solid #e5e7eb; margin:10px 0 20px 0;"></td></tr>

            <tr>
              <td style="padding:0 16px 10px 16px;">
                <div style="font-size:20px; font-weight:800; color:#111827; margin:8px 0 14px 2px;">
                  Worth testing
