            <tr><td style="padding:0 16px 8px 16px;"><hr style="border:none; border-top:1px solid #e5e7eb; margin:10px 0 20px 0;"></td></tr>

            <tr>
              <td style="padding:0 16px 10px 16px;">
                <div style="font-size:20px; font-weight:800; color:#111827; margin:8px 0 14px 2px;">
                  Worth watching
                </div>
                ${watchSection}
              </td>
            </tr>

            <tr>
              <td style="padding:8px 16px 22px 16px;">
                <div style="font-size:12px; color:#6b7280; text-align:center; line-height:1.6;">
                  Generated automatically by AI Tool Radar with n8n.
                </div>
