const repos = $json.items || [];

return repos.map(repo => {
  return {
    json: {
      title: repo.name,
      source: "GitHub",
      summary: repo.description || "",
      url: repo.html_url,
      published_date: repo.created_at,
      created_at: new Date().toISOString(),
      status: "New"
    }
  };
});

const feed = $json.feed || $json;
let entries = feed.entry || [];

if (!Array.isArray(entries)) {
  entries = [entries];
}

return entries.map(entry => {
  const title = entry.title?._text || entry.title || "";
  const summary = entry.summary?._text || entry.summary || "";
  const published = entry.published?._text || entry.published || "";
  const url = entry.id?._text || entry.id || "";

  return {
    json: {
      title: String(title).replace(/\s+/g, " ").trim(),
      source: "arXiv",
      summary: String(summary).replace(/\s+/g, " ").trim().slice(0, 500),
      url: String(url),
      published_date: String(published),
      created_at: new Date().toISOString(),
      status: "New"
    }
  };
});

const items = $input.all();

const keywords = [
  "ai", "artificial intelligence", "llm", "gpt",
  "agent", "agents", "rag", "multimodal",
  "model", "models", "machine learning", "ml",
  "genai", "generative", "embedding",
  "fine-tuning", "inference", "vision", "voice"
];

function scoreItem(item) {
  const title = (item.json.title || "").toLowerCase();
  const summary = (item.json.summary || "").toLowerCase();
  const text = `${title} ${summary}`;

  let score = 0;
  for (const k of keywords) {
    if (text.includes(k)) score += 2;
  }

  const source = item.json.source || "";
  if (source === "ProductHunt") score += 3;
  if (source === "GitHub") score += 2;
  if (source === "arXiv") score += 2;
  if (source === "HackerNews") score += 1;

  return score;
}

// deduplicate by URL
const seen = new Set();
const deduped = items.filter(item => {
  const url = item.json.url || "";
  if (!url) return true;
  if (seen.has(url)) return false;
  seen.add(url);
  return true;
});

// keep only AI-relevant items
const relevant = deduped.filter(item => {
  const title = (item.json.title || "").toLowerCase();
  const summary = (item.json.summary || "").toLowerCase();
  const text = `${title} ${summary}`;
  return keywords.some(k => text.includes(k));
});

// group by source
const groups = {
  ProductHunt: [],
  GitHub: [],
  arXiv: [],
  HackerNews: []
};

for (const item of relevant) {
  const source = item.json.source || "";
  if (groups[source]) {
    groups[source].push({ item, score: scoreItem(item) });
  }
}

// sort inside each group
for (const source of Object.keys(groups)) {
  groups[source].sort((a, b) => b.score - a.score);
}

// new quotas
const limits = {
  ProductHunt: 3,
  GitHub: 2,
  arXiv: 2,
  HackerNews: 1
};

let selected = [];

for (const source of Object.keys(limits)) {
  selected.push(...groups[source].slice(0, limits[source]).map(x => x.item));
}

// fill remaining slots up to 8 from leftovers
if (selected.length < 8) {
  const selectedUrls = new Set(selected.map(x => x.json.url || ""));
  const leftovers = [];

  for (const source of Object.keys(groups)) {
    for (const x of groups[source]) {
      const url = x.item.json.url || "";
      if (!selectedUrls.has(url)) leftovers.push(x);
    }
  }

  leftovers.sort((a, b) => b.score - a.score);

  for (const x of leftovers) {
    if (selected.length >= 8) break;
    selected.push(x.item);
  }
}

return selected;

const rows = $input.all().map(item => item.json);

const cleaned = rows
  .filter(row =>
    row.title &&
    row.title !== "title" &&
    row.final_score !== "" &&
    row.final_score !== "final_score"
  )
  .map(row => ({
    id: row.id || "",
    hash_id: row.hash_id || "",
    title: row.title || "",
    source: row.source || "",
    category: row.category || "",
    published_date: row.published_date || "",
    url: row.url || "",
    summary: row.summary || "",
    lab_relevance: Number(row.lab_relevance || 0),
    practicality: Number(row.practicality || 0),
    novelty: Number(row.novelty || 0),
    final_score: Number(row.final_score || 0),
    recommended_action: row.recommended_action || "",
    why_it_matters: row.why_it_matters || "",
    status: row.status || "",
    created_at: row.created_at || ""
  }))
  .sort((a, b) => b.final_score - a.final_score);

const uniqueByHash = [];
const seen = new Set();
for (const row of cleaned) {
  const key = row.hash_id || row.url || row.title;
  if (!key) continue;
  if (seen.has(key)) continue;
  seen.add(key);
  uniqueByHash.push(row);
}

const duplicateRowsRemoved = Math.max(0, cleaned.length - uniqueByHash.length);

const lastCollectorRun = uniqueByHash.reduce((latest, row) => {
  const t = new Date(row.created_at || 0).getTime();
  if (!Number.isFinite(t)) return latest;
  return t > latest ? t : latest;
}, 0);

return [
  {
    json: {
      meta: {
        generated_at: new Date().toISOString(),
        total_rows: cleaned.length,
        unique_rows: uniqueByHash.length,
        duplicate_rows_removed: duplicateRowsRemoved,
        upsert_key: "hash_id",
        last_collector_run: lastCollectorRun ? new Date(lastCollectorRun).toISOString() : ""
      },
      data: uniqueByHash
    }
  }
];
